class Solution:
    def maxProfit(self, prices):
        n = len(prices)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def best(i, holding):
            if i >= n:
                return 0
            skip = best(i + 1, holding)
            if holding:
                act = prices[i] + best(i + 2, False)
            else:
                act = -prices[i] + best(i + 1, True)
            return max(skip, act)
        return best(0, False)

